#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,INF=1e9;

struct Node{
    int s[2],v,f,sz;
    void init(int _v,int _f){
        v=_v,f=_f;
        sz=1;
    }
}t[N];

int n,m,root,tot,delta,cnt;

void pushup(int x){
    t[x].sz=t[t[x].s[0]].sz+1+t[t[x].s[1]].sz;
}

void Rotate(int x){
    int y=t[x].f,z=t[y].f,k=(t[y].s[1]==x);
    t[z].s[t[z].s[1]==y]=x,t[x].f=z;
    t[y].s[k]=t[x].s[k^1],t[t[x].s[k^1]].f=y;
    t[x].s[k^1]=y,t[y].f=x;
    pushup(y),pushup(x);
}

void Splay(int x,int k){
    while(t[x].f!=k){
        int y=t[x].f,z=t[y].f;
        if(z!=k)
            if((x==t[y].s[1])^(y==t[z].s[1])) Rotate(x);
            else Rotate(y);
        Rotate(x);
    }
    if(!k) root=x;
}

void Insert(int v){
    int u=root,p=0;
    while(u)
        p=u,u=t[u].s[v>t[u].v];
    u=++tot;
    t[u].init(v,p);
    if(p) t[p].s[v>t[p].v]=u;
    Splay(u,0);
}

int getv(int v){
    int u=root,res;
    while(u){
        if(t[u].v>=v) res=u,u=t[u].s[0];
        else u=t[u].s[1];
    }
    return res;
}

int get_k(int k){
    int u=root;
    while(u){
        if(t[t[u].s[0]].sz>=k) u=t[u].s[0];
        else if(t[t[u].s[0]].sz+1==k) return t[u].v;
        else k-=t[t[u].s[0]].sz+1,u=t[u].s[1];
    }
    return -1;
}

int main(){
    scanf("%d%d",&n,&m);
    Insert(-INF),Insert(INF);
    while(n--){
        char op[2];
        int k;
        scanf("%s",op);
        scanf("%d",&k);
        if(op[0]=='I'){
            if(k>=m)
                Insert(k-delta);
        }else if(op[0]=='A')
            delta+=k;
        else if(op[0]=='S'){
            delta-=k;
            int r=getv(m-delta);
            Splay(1,0),Splay(r,1);
            cnt+=t[t[r].s[0]].sz;
            t[r].s[0]=0;
            pushup(r),pushup(1);
        }else{
            if(k>t[root].sz-2)
                puts("-1");
            else
                printf("%d\n",get_k(t[root].sz-k)+delta);
        }
    }
    printf("%d",cnt);
    return 0;
}
